// UNPATCHED AfdSanAcceptCore - vulnerable memmove paths (0x1c007508c)

// rbx_4 = *(arg1 + 0xb8) = accept info structure
// rbx_4+0x8 = AddressBuffer pointer (MDL-mapped destination)
// rbx_4+0x10 = AddressBufferLength (capacity - NEVER CHECKED against copy size)
// rbx_4+0x18 = AddressOffset
// MasterIrp+0x14 = remote transport address length (ATTACKER CONTROLLED)

// PATH 1: !*(r13+0xac) (non-TDI address)
if (*(rbx_4 + 0x10) > 0)  // ONLY checks > 0!
{
    uint32_t r12_1 = *(MasterIrp + 0x14);  // attacker-controlled length
    Irql = r12_1 + 8;                       // size = len + 8 (NO BOUNDS CHECK!)
    ...
    memmove(*(rbx_4 + 8) + *(rbx_4 + 0x18) + MappedSystemVa_3,
           MasterIrp_1 + 0x10, Irql);       // OVERFLOW: copies len+8 into buffer
}

// PATH 2: *(r13+0xac) (TDI address)
else
{
    r12_1 += 2;  // size = len + 2 (NO BOUNDS CHECK!)
    ...
    memmove(*(rbx_4 + 8) + *(rbx_4 + 0x18) + MappedSystemVa_2,
           MasterIrp + 0x16, r12_1);        // OVERFLOW: copies len+2 into buffer
}

// PATH 3: secondary address copy, !*(r13+0xac)
if (*(rbx_4 + 0x18) > 0)
{
    r12_2 = MasterIrp_1 + *(MasterIrp_1 + 0x14);
    ...
    memmove(r14_2 + 8, r12_2 + 0x18,
           *(r12_2 + 0x18) + 4);            // OVERFLOW: copies len+4
}

// PATH 4: secondary address copy, *(r13+0xac)
else
{
    memmove(r14_2, r12_2 + 0x1a,
           *(r12_2 + 0x18) + 2);            // OVERFLOW: copies len+2
}
